export const EXCEL_PIVOT_STYLES_BY_NAME = new Map(
  EXCEL_PIVOT_STYLES.map((s) => [s.name, s]),
);

/** The default pivot style (matches Excel default). */
export const DEFAULT_EXCEL_PIVOT_STYLE = 'PivotStyleLight16';

